import{_ as e,c as o,o as a,a1 as i}from"./chunks/framework.DILC4Csi.js";const p=JSON.parse('{"title":"429: 账号轮转 | Antigravity-Manager","description":"学习 Antigravity-Manager 的 429 错误处理。了解配额耗尽、速率限制和模型容量不足的区分，掌握账号轮转机制和监控工具使用。","frontmatter":{"title":"429: 账号轮转 | Antigravity-Manager","sidebarTitle":"429 轮转","subtitle":"429: 账号轮转","description":"学习 Antigravity-Manager 的 429 错误处理。了解配额耗尽、速率限制和模型容量不足的区分，掌握账号轮转机制和监控工具使用。","tags":["FAQ","Troubleshooting","Account Scheduling","429 Error"],"prerequisite":["start-getting-started","advanced-scheduling"],"order":999},"headers":[],"relativePath":"lbjlaq/Antigravity-Manager/faq/429-rotation/index.md","filePath":"lbjlaq/Antigravity-Manager/faq/429-rotation/index.md"}'),r={name:"lbjlaq/Antigravity-Manager/faq/429-rotation/index.md"};function n(s,t,c,l,d,u){return a(),o("div",null,[...t[0]||(t[0]=[i(`<h1 id="_429-capacity-errors-correct-expectations-for-account-rotation-and-model-capacity-myths" tabindex="-1">429/Capacity Errors: Correct Expectations for Account Rotation and Model Capacity Myths <a class="header-anchor" href="#_429-capacity-errors-correct-expectations-for-account-rotation-and-model-capacity-myths" aria-label="Permalink to &quot;429/Capacity Errors: Correct Expectations for Account Rotation and Model Capacity Myths&quot;">​</a></h1><h2 id="what-you-ll-learn" tabindex="-1">What You&#39;ll Learn <a class="header-anchor" href="#what-you-ll-learn" aria-label="Permalink to &quot;What You&#39;ll Learn&quot;">​</a></h2><ul><li>Correctly distinguish between &quot;quota exhaustion&quot; and &quot;upstream rate limiting&quot; to avoid misdiagnosis</li><li>Understand Antigravity Tools&#39; automatic rotation mechanism and expected behavior</li><li>Know how to quickly pinpoint issues and optimize configuration when encountering 429 errors</li></ul><h2 id="your-current-struggles" tabindex="-1">Your Current Struggles <a class="header-anchor" href="#your-current-struggles" aria-label="Permalink to &quot;Your Current Struggles&quot;">​</a></h2><ul><li>Seeing a 429 error and mistakenly assuming &quot;the model is out of capacity&quot;</li><li>Having multiple accounts configured but still frequently encountering 429, unsure if it&#39;s a configuration or account issue</li><li>Unclear when the system automatically switches accounts versus when it &quot;gets stuck&quot;</li></ul><h2 id="core-approach" tabindex="-1">Core Approach <a class="header-anchor" href="#core-approach" aria-label="Permalink to &quot;Core Approach&quot;">​</a></h2><h3 id="what-is-a-429-error" tabindex="-1">What is a 429 Error? <a class="header-anchor" href="#what-is-a-429-error" aria-label="Permalink to &quot;What is a 429 Error?&quot;">​</a></h3><p><strong>429 Too Many Requests</strong> is an HTTP status code. In Antigravity Tools, 429 doesn&#39;t just mean &quot;requests too frequent&quot;—it can also be a signal like &quot;you can&#39;t use this temporarily&quot; due to quota exhaustion, temporary model overload, and similar issues.</p><div class="info custom-block"><p class="custom-block-title">The proxy attempts to identify the cause of 429</p><p>The proxy tries to parse <code>error.details[0].reason</code> or <code>error.message</code> from the response body, roughly categorizing 429 into several types (actual classification depends on the returned data):</p><table tabindex="0"><thead><tr><th>Type identified by proxy</th><th>Common reason / clues</th><th>Typical characteristics</th></tr></thead><tbody><tr><td><strong>Quota exhausted</strong></td><td><code>QUOTA_EXHAUSTED</code> / Text contains <code>exhausted</code>, <code>quota</code></td><td>May need to wait for quota to refresh</td></tr><tr><td><strong>Rate limited</strong></td><td><code>RATE_LIMIT_EXCEEDED</code> / Text contains <code>per minute</code>, <code>rate limit</code>, <code>too many requests</code></td><td>Usually cooldown at the tens-of-seconds level</td></tr><tr><td><strong>Model capacity insufficient</strong></td><td><code>MODEL_CAPACITY_EXHAUSTED</code> / Text contains <code>model_capacity</code></td><td>Commonly temporary overload, recoverable shortly</td></tr><tr><td><strong>Unknown</strong></td><td>Cannot parse</td><td>Follows default cooldown strategy</td></tr></tbody></table></div><h3 id="antigravity-tools-automatic-handling" tabindex="-1">Antigravity Tools&#39; Automatic Handling <a class="header-anchor" href="#antigravity-tools-automatic-handling" aria-label="Permalink to &quot;Antigravity Tools&#39; Automatic Handling&quot;">​</a></h3><p>When a request encounters 429 (and some 5xx/overload statuses), the proxy typically does two things on the server side:</p><ol><li><strong>Record cooldown time</strong>: Writes this error to <code>RateLimitTracker</code>, and when selecting accounts subsequently, it will actively avoid accounts that are &quot;still cooling down.&quot;</li><li><strong>Rotate accounts in retries</strong>: Handlers perform multiple attempts within a single request, and when retrying, will use <code>force_rotate=true</code>, triggering TokenManager to select the next available account.</li></ol><div class="tip custom-block"><p class="custom-block-title">How do you know if it switched accounts?</p><p>Even if your request body doesn&#39;t change, the response usually includes <code>X-Account-Email</code> (as well as <code>X-Mapped-Model</code>), which you can use to verify &quot;which account this request actually used.&quot;</p></div><h2 id="when-do-you-encounter-429-errors" tabindex="-1">When Do You Encounter 429 Errors? <a class="header-anchor" href="#when-do-you-encounter-429-errors" aria-label="Permalink to &quot;When Do You Encounter 429 Errors?&quot;">​</a></h2><h3 id="scenario-1-single-account-requests-too-fast" tabindex="-1">Scenario 1: Single Account Requests Too Fast <a class="header-anchor" href="#scenario-1-single-account-requests-too-fast" aria-label="Permalink to &quot;Scenario 1: Single Account Requests Too Fast&quot;">​</a></h3><p><strong>Phenomenon</strong>: Even with only one account, sending a large number of requests in a short time triggers 429.</p><p><strong>Cause</strong>: Each account has its own rate limit (RPM/TPM); exceeding it results in throttling.</p><p><strong>Solution</strong>:</p><ul><li>Increase the number of accounts</li><li>Lower request frequency</li><li>Use fixed account mode to distribute pressure (see &quot;Fixed Account Mode&quot; for details)</li></ul><h3 id="scenario-2-all-accounts-rate-limited-simultaneously" tabindex="-1">Scenario 2: All Accounts Rate-Limited Simultaneously <a class="header-anchor" href="#scenario-2-all-accounts-rate-limited-simultaneously" aria-label="Permalink to &quot;Scenario 2: All Accounts Rate-Limited Simultaneously&quot;">​</a></h3><p><strong>Phenomenon</strong>: Multiple accounts exist, but all return 429.</p><p><strong>Causes</strong>:</p><ul><li>Total account count is insufficient to support your request frequency</li><li>All accounts trigger rate limiting/overload at nearly the same time</li></ul><p><strong>Solution</strong>:</p><ul><li>Add more accounts</li><li>Adjust scheduling mode to &quot;PerformanceFirst&quot; (skip sticky sessions and 60s window reuse)</li><li>Check if quota protection mistakenly excludes available accounts</li></ul><h3 id="scenario-3-account-mistakenly-blocked-by-quota-protection" tabindex="-1">Scenario 3: Account Mistakenly Blocked by Quota Protection <a class="header-anchor" href="#scenario-3-account-mistakenly-blocked-by-quota-protection" aria-label="Permalink to &quot;Scenario 3: Account Mistakenly Blocked by Quota Protection&quot;">​</a></h3><p><strong>Phenomenon</strong>: An account has sufficient quota, but the system keeps skipping it.</p><p><strong>Causes</strong>:</p><ul><li><strong>Quota protection</strong> is enabled, and the threshold is set too high</li><li>That account&#39;s specific model quota is below the threshold</li><li>The account is manually marked as <code>proxy_disabled</code></li></ul><p><strong>Solution</strong>:</p><ul><li>Check quota protection settings (Settings → Quota Protection), adjust thresholds and monitored models according to your usage intensity</li><li>In account data, check <code>protected_models</code> to confirm if it&#39;s being skipped by protection policy</li></ul><h2 id="follow-me" tabindex="-1">Follow Me <a class="header-anchor" href="#follow-me" aria-label="Permalink to &quot;Follow Me&quot;">​</a></h2><h3 id="step-1-identify-the-429-error-type" tabindex="-1">Step 1: Identify the 429 Error Type <a class="header-anchor" href="#step-1-identify-the-429-error-type" aria-label="Permalink to &quot;Step 1: Identify the 429 Error Type&quot;">​</a></h3><p><strong>Why</strong>: Different types of 429 errors require different handling approaches.</p><p>Check the response body of the 429 error in Proxy Monitor, focusing on two types of information:</p><ul><li><strong>Reason</strong>: <code>error.details[0].reason</code> (e.g., <code>RATE_LIMIT_EXCEEDED</code>, <code>QUOTA_EXHAUSTED</code>) or <code>error.message</code></li><li><strong>Wait time</strong>: <code>RetryInfo.retryDelay</code> or <code>details[0].metadata.quotaResetDelay</code> (if present)</li></ul><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;error&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;details&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: [</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">      {</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">        &quot;reason&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;RATE_LIMIT_EXCEEDED&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">        &quot;metadata&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">          &quot;quotaResetDelay&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;42s&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">        }</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">      }</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    ]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  }</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p><strong>You should see</strong>:</p><ul><li>If the response body contains wait time (e.g., <code>RetryInfo.retryDelay</code> or <code>quotaResetDelay</code>), the proxy typically waits a short period before retrying.</li><li>If there&#39;s no wait time, the proxy adds a &quot;cooldown period&quot; to this account according to built-in strategy and directly switches to the next account during retry.</li></ul><h3 id="step-2-check-account-scheduling-configuration" tabindex="-1">Step 2: Check Account Scheduling Configuration <a class="header-anchor" href="#step-2-check-account-scheduling-configuration" aria-label="Permalink to &quot;Step 2: Check Account Scheduling Configuration&quot;">​</a></h3><p><strong>Why</strong>: Scheduling configuration directly affects account rotation frequency and priority.</p><p>Go to the <strong>API Proxy</strong> page and view scheduling strategy:</p><table tabindex="0"><thead><tr><th>Configuration</th><th>Description</th><th>Default/Suggested</th></tr></thead><tbody><tr><td><strong>Scheduling Mode</strong></td><td>Scheduling mode</td><td><code>Balance</code> (default)</td></tr><tr><td><strong>Preferred Account</strong></td><td>Fixed account mode</td><td>Unchecked (default)</td></tr></tbody></table><p><strong>Scheduling Mode Comparison</strong>:</p><table tabindex="0"><thead><tr><th>Mode</th><th>Account Reuse Strategy</th><th>Rate Limit Handling</th><th>Applicable Scenarios</th></tr></thead><tbody><tr><td><strong>CacheFirst</strong></td><td>Enables sticky sessions and 60s window reuse</td><td><strong>Prioritizes waiting</strong>, greatly improving Prompt Caching hit rate</td><td>Conversational/high cache hit rate requirements</td></tr><tr><td><strong>Balance</strong></td><td>Enables sticky sessions and 60s window reuse</td><td><strong>Immediately switches</strong> to backup accounts, balancing success rate and performance</td><td>General scenarios, default</td></tr><tr><td><strong>PerformanceFirst</strong></td><td>Skips sticky sessions and 60s window reuse, pure round-robin</td><td>Immediately switches, most balanced account load</td><td>High concurrency, stateless requests</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">CacheFirst vs Balance Mode</p><p>If you use Prompt Caching and want to improve cache hit rates, choose <code>CacheFirst</code> — when rate limited, it prioritizes waiting rather than immediately switching accounts. If you value request success rate more than caching, choose <code>Balance</code> — when rate limited, it immediately switches accounts.</p></div><div class="tip custom-block"><p class="custom-block-title">PerformanceFirst Mode</p><p>If your requests are stateless (like image generation, independent queries), try <code>PerformanceFirst</code>. It skips sticky sessions and 60s window reuse, making consecutive requests more likely to land on different accounts.</p></div><h3 id="step-3-verify-account-rotation-is-working-correctly" tabindex="-1">Step 3: Verify Account Rotation Is Working Correctly <a class="header-anchor" href="#step-3-verify-account-rotation-is-working-correctly" aria-label="Permalink to &quot;Step 3: Verify Account Rotation Is Working Correctly&quot;">​</a></h3><p><strong>Why</strong>: Confirm the system can automatically switch accounts.</p><p><strong>Method 1: Check Response Headers</strong></p><p>Use curl or your own client to print response headers, observe whether <code>X-Account-Email</code> changes.</p><p><strong>Method 2: View Logs</strong></p><p>Open the log file (depending on your system location), search for <code>🔄 [Token Rotation]</code>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>🔄 [Token Rotation] Accounts: [</span></span>
<span class="line"><span>  &quot;account1@example.com(protected=[])&quot;,</span></span>
<span class="line"><span>  &quot;account2@example.com(protected=[])&quot;,</span></span>
<span class="line"><span>  &quot;account3@example.com(protected=[])&quot;</span></span>
<span class="line"><span>]</span></span></code></pre></div><p><strong>Method 3: Use Proxy Monitor</strong></p><p>On the <strong>Monitor</strong> page, check request logs, focusing on:</p><ul><li>Whether the <strong>Account</strong> field switches between different accounts</li><li>After requests with <strong>Status</strong> 429, whether successful requests use different accounts</li></ul><p><strong>You should see</strong>:</p><ul><li>When an account returns 429, subsequent requests automatically switch to other accounts</li><li>If you see multiple requests using the same account and all failing, it might be a scheduling configuration issue</li></ul><h3 id="step-4-optimize-account-priority" tabindex="-1">Step 4: Optimize Account Priority <a class="header-anchor" href="#step-4-optimize-account-priority" aria-label="Permalink to &quot;Step 4: Optimize Account Priority&quot;">​</a></h3><p><strong>Why</strong>: Make the system prioritize high quota/high tier accounts to reduce 429 probability.</p><p>In TokenManager, the system performs a sort on the account pool before selecting accounts (will print <code>🔄 [Token Rotation] Accounts: ...</code>):</p><ol><li><strong>Subscription tier priority</strong>: ULTRA &gt; PRO &gt; FREE</li><li><strong>Quota percentage priority</strong>: Within the same tier, higher quota comes first</li><li><strong>Sort entry</strong>: This sorting happens on the proxy side. Which account is ultimately used depends on proxy-side sorting + availability judgment.</li></ol><div class="info custom-block"><p class="custom-block-title">Smart Sorting Principle (Proxy Side)</p><p>Priority is <code>ULTRA &gt; PRO &gt; FREE</code>; within the same subscription tier, descending by <code>remaining_quota</code> (account&#39;s maximum remaining quota percentage).</p></div><p><strong>Actions</strong>:</p><ul><li>Drag accounts to adjust display order (optional)</li><li>Refresh quota (Accounts → Refresh All Quota)</li><li>Check account subscription tiers and quota</li></ul><h2 id="pitfall-reminders" tabindex="-1">Pitfall Reminders <a class="header-anchor" href="#pitfall-reminders" aria-label="Permalink to &quot;Pitfall Reminders&quot;">​</a></h2><h3 id="❌-mistake-1-mistaking-429-for-model-out-of-capacity" tabindex="-1">❌ Mistake 1: Mistaking 429 for &quot;Model Out of Capacity&quot; <a class="header-anchor" href="#❌-mistake-1-mistaking-429-for-model-out-of-capacity" aria-label="Permalink to &quot;❌ Mistake 1: Mistaking 429 for &quot;Model Out of Capacity&quot;&quot;">​</a></h3><p><strong>Phenomenon</strong>: Seeing a 429 error and assuming the model is out of capacity.</p><p><strong>Correct Understanding</strong>:</p><ul><li>429 is <strong>rate limiting</strong>, not a capacity issue</li><li>Adding more accounts can reduce 429 probability</li><li>Adjusting scheduling mode can improve switch speed</li></ul><h3 id="❌-mistake-2-quota-protection-threshold-set-too-high" tabindex="-1">❌ Mistake 2: Quota Protection Threshold Set Too High <a class="header-anchor" href="#❌-mistake-2-quota-protection-threshold-set-too-high" aria-label="Permalink to &quot;❌ Mistake 2: Quota Protection Threshold Set Too High&quot;">​</a></h3><p><strong>Phenomenon</strong>: Quota is sufficient but the system keeps skipping accounts.</p><p><strong>Cause</strong>: Quota Protection adds models below the threshold to the account&#39;s <code>protected_models</code>, and the proxy skips &quot;protected models&quot; during scheduling. When the threshold is too high, available accounts may be overly excluded.</p><p><strong>Fix</strong>:</p><ul><li>Go back to <strong>Settings → Quota Protection</strong>, adjust monitored models and thresholds</li><li>If you want to know exactly which models it&#39;s protecting, check <code>protected_models</code> in account data</li></ul><h3 id="❌-mistake-3-fixed-account-mode-prevents-rotation" tabindex="-1">❌ Mistake 3: Fixed Account Mode Prevents Rotation <a class="header-anchor" href="#❌-mistake-3-fixed-account-mode-prevents-rotation" aria-label="Permalink to &quot;❌ Mistake 3: Fixed Account Mode Prevents Rotation&quot;">​</a></h3><p><strong>Phenomenon</strong>: Set <code>Preferred Account</code>, but when that account is rate limited, the system &quot;gets stuck.&quot;</p><p><strong>Cause</strong>: In fixed account mode, the system prioritizes using the specified account, only falling back to round-robin when the account is unavailable.</p><p><strong>Fix</strong>:</p><ul><li>If you don&#39;t need a fixed account, clear <code>Preferred Account</code></li><li>Or ensure the fixed account has sufficient quota to avoid rate limiting</li></ul><h2 id="checkpoints-✅" tabindex="-1">Checkpoints ✅ <a class="header-anchor" href="#checkpoints-✅" aria-label="Permalink to &quot;Checkpoints ✅&quot;">​</a></h2><ul><li>[ ] Can distinguish between quota exhaustion and upstream rate limiting</li><li>[ ] Know how to view 429 error details in Proxy Monitor</li><li>[ ] Understand the differences and use cases for the three scheduling modes</li><li>[ ] Know how to check if account rotation is working correctly</li><li>[ ] Can optimize account priority and check quota protection policies</li></ul><h2 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ&quot;">​</a></h2><h3 id="q1-why-do-i-still-encounter-429-even-with-multiple-accounts" tabindex="-1">Q1: Why do I still encounter 429 even with multiple accounts? <a class="header-anchor" href="#q1-why-do-i-still-encounter-429-even-with-multiple-accounts" aria-label="Permalink to &quot;Q1: Why do I still encounter 429 even with multiple accounts?&quot;">​</a></h3><p>A: Possible reasons:</p><ol><li>All accounts triggered rate limiting simultaneously (request frequency too high)</li><li>Consecutive requests repeatedly reuse the same account under &quot;60s window reuse&quot;, more likely to hit rate limits on a single account</li><li>Quota protection incorrectly excludes available accounts</li><li>Total account count is insufficient to support your request frequency</li></ol><p><strong>Solutions</strong>:</p><ul><li>Add more accounts</li><li>Use <code>PerformanceFirst</code> mode</li><li>Check if Quota Protection added the models you want to use to <code>protected_models</code> (adjust monitored models and thresholds if necessary)</li><li>Lower request frequency</li></ul><h3 id="q2-do-429-errors-automatically-retry" tabindex="-1">Q2: Do 429 errors automatically retry? <a class="header-anchor" href="#q2-do-429-errors-automatically-retry" aria-label="Permalink to &quot;Q2: Do 429 errors automatically retry?&quot;">​</a></h3><p>A: Yes, they automatically retry within a single request. <strong>Retry limit is typically 3 times</strong>, calculated as <code>min(3, account pool size)</code>, with at least 1 attempt.</p><p><strong>Retry Count Examples</strong>:</p><ul><li>Account pool 1 account → Attempt 1 time (no retry)</li><li>Account pool 2 accounts → Attempt 2 times (retry 1 time)</li><li>Account pool 3 or more accounts → Attempt 3 times (retry 2 times)</li></ul><p><strong>Rough Flow</strong>:</p><ol><li>Record rate limit/overload information (enter <code>RateLimitTracker</code>)</li><li>If wait time can be parsed (e.g., <code>RetryInfo.retryDelay</code> / <code>quotaResetDelay</code>), wait a short period before continuing</li><li>During retry, force rotate account (when <code>attempt &gt; 0</code>, <code>force_rotate=true</code>), attempting to initiate upstream request with the next available account</li></ol><p>If all attempts fail, the proxy returns the error to the client. Meanwhile, you can still see the actually used accounts from response headers (like <code>X-Account-Email</code>) or Proxy Monitor.</p><h3 id="q3-how-do-i-check-how-long-an-account-has-been-rate-limited" tabindex="-1">Q3: How do I check how long an account has been rate limited? <a class="header-anchor" href="#q3-how-do-i-check-how-long-an-account-has-been-rate-limited" aria-label="Permalink to &quot;Q3: How do I check how long an account has been rate limited?&quot;">​</a></h3><p>A: Two methods:</p><p><strong>Method 1</strong>: Check logs, search for <code>rate-limited</code></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>🔒 [FIX #820] Preferred account xxx@gmail.com is rate-limited, falling back to round-robin</span></span></code></pre></div><p><strong>Method 2</strong>: Logs show remaining wait time</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>All accounts are currently limited. Please wait 30s.</span></span></code></pre></div><h3 id="q4-are-quota-protection-and-rate-limiting-the-same-thing" tabindex="-1">Q4: Are quota protection and rate limiting the same thing? <a class="header-anchor" href="#q4-are-quota-protection-and-rate-limiting-the-same-thing" aria-label="Permalink to &quot;Q4: Are quota protection and rate limiting the same thing?&quot;">​</a></h3><p>A: No.</p><table tabindex="0"><thead><tr><th>Feature</th><th>Quota Protection</th><th>Rate Limit Tracking</th></tr></thead><tbody><tr><td><strong>Trigger Condition</strong></td><td>Model quota below threshold</td><td>Received 429 error</td></tr><tr><td><strong>Scope</strong></td><td>Specific models</td><td>Entire account</td></tr><tr><td><strong>Duration</strong></td><td>Until quota recovers</td><td>Determined by upstream (usually seconds to minutes)</td></tr><tr><td><strong>Behavior</strong></td><td>Skip that model</td><td>Skip that account</td></tr></tbody></table><h3 id="q5-how-do-i-force-immediate-account-switching" tabindex="-1">Q5: How do I force immediate account switching? <a class="header-anchor" href="#q5-how-do-i-force-immediate-account-switching" aria-label="Permalink to &quot;Q5: How do I force immediate account switching?&quot;">​</a></h3><p>A: Approach it from &quot;making the next request more likely to switch&quot;:</p><ol><li><strong>Scheduling level</strong>: Switch to <code>PerformanceFirst</code>, skip sticky sessions and 60s window reuse</li><li><strong>Fixed account</strong>: If <code>Preferred Account</code> is enabled, clear it first, otherwise it will prioritize the fixed account (until it&#39;s rate limited/protected)</li><li><strong>Account pool</strong>: Increase account count, making it easier to find an alternative account when one is rate limited</li></ol><p>Within a single request, the proxy also force rotates during retries (when <code>attempt &gt; 0</code>, it triggers <code>force_rotate=true</code>), but retry count is limited by an upper bound.</p><h2 id="lesson-summary" tabindex="-1">Lesson Summary <a class="header-anchor" href="#lesson-summary" aria-label="Permalink to &quot;Lesson Summary&quot;">​</a></h2><ul><li>In Antigravity Tools, 429 is a category of &quot;upstream temporarily unavailable&quot; signals, possibly caused by rate limiting, quota exhaustion, model capacity insufficiency, etc.</li><li>The proxy records cooldown time and attempts to rotate accounts during retries within a single request (but retry count is limited)</li><li>Scheduling mode, Quota Protection, and account count all affect the probability of encountering 429 and recovery speed</li><li>Use Proxy Monitor, response header <code>X-Account-Email</code>, and logs to quickly pinpoint issues</li></ul><h2 id="next-lesson-preview" tabindex="-1">Next Lesson Preview <a class="header-anchor" href="#next-lesson-preview" aria-label="Permalink to &quot;Next Lesson Preview&quot;">​</a></h2><blockquote><p>In the next lesson, we&#39;ll learn <strong><a href="./../404-base-url/">404/Path Incompatibility: Base URL, /v1 Prefix &amp; Stacked Path Clients</a></strong></p><p>You&#39;ll learn:</p><ul><li>How the most common integration error (404) occurs</li><li>Different clients&#39; base_url concatenation differences</li><li>How to quickly fix 404 issues</li></ul></blockquote><hr><h2 id="appendix-source-code-reference" tabindex="-1">Appendix: Source Code Reference <a class="header-anchor" href="#appendix-source-code-reference" aria-label="Permalink to &quot;Appendix: Source Code Reference&quot;">​</a></h2><details><summary><strong>Click to expand source code locations</strong></summary><blockquote><p>Updated: 2026-01-23</p></blockquote><table tabindex="0"><thead><tr><th>Feature</th><th>File Path</th><th>Line Numbers</th></tr></thead><tbody><tr><td>429 retry delay parsing (RetryInfo / quotaResetDelay)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/upstream/retry.rs#L38-L67" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/upstream/retry.rs</code></a></td><td>38-67</td></tr><tr><td>Duration parsing utility</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/upstream/retry.rs#L11-L35" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/upstream/retry.rs</code></a></td><td>11-35</td></tr><tr><td>Scheduling mode enum (CacheFirst/Balance/PerformanceFirst)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/sticky_config.rs#L3-L12" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/sticky_config.rs</code></a></td><td>3-12</td></tr><tr><td>Rate limit reason parsing and default cooldown strategy</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/rate_limit.rs#L5-L258" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/rate_limit.rs</code></a></td><td>5-258</td></tr><tr><td>MAX_RETRY_ATTEMPTS constant definition (OpenAI handler)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/handlers/openai.rs#L14" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/handlers/openai.rs</code></a></td><td>14</td></tr><tr><td>Retry count calculation (max_attempts = min(MAX_RETRY_ATTEMPTS, pool_size))</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/handlers/openai.rs#L830" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/handlers/openai.rs</code></a></td><td>830</td></tr><tr><td>OpenAI handler: mark rate limit and retry/rotate on 429/5xx</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/handlers/openai.rs#L349-L389" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/handlers/openai.rs</code></a></td><td>349-389</td></tr><tr><td>Account sorting priority (ULTRA &gt; PRO &gt; FREE + remaining_quota)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/token_manager.rs#L504-L538" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/token_manager.rs</code></a></td><td>504-538</td></tr><tr><td>60s window reuse + avoid rate limit/quota protection</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/token_manager.rs#L624-L739" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/token_manager.rs</code></a></td><td>624-739</td></tr><tr><td>Rate limit record entry (mark_rate_limited)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/token_manager.rs#L1089-L1113" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/token_manager.rs</code></a></td><td>1089-1113</td></tr><tr><td>---</td><td>---</td><td>---</td></tr></tbody></table><p><strong>Key Constants</strong>:</p><ul><li><code>MAX_RETRY_ATTEMPTS = 3</code>: Maximum retry count within a single request (OpenAI/Gemini handler)</li><li><code>60</code>: 60-second window reuse (only enabled in modes other than <code>PerformanceFirst</code>)</li><li><code>5</code>: Token fetch timeout (seconds)</li><li><code>300</code>: Token early refresh threshold (seconds, 5 minutes)</li></ul><p><strong>Key Functions</strong>:</p><ul><li><code>parse_retry_delay()</code>: Extracts retry delay from 429 error response</li><li><code>get_token_internal()</code>: Core logic for account selection and rotation</li><li><code>mark_rate_limited()</code>: Marks account as rate limited</li></ul></details>`,116)])])}const g=e(r,[["render",n]]);export{p as __pageData,g as default};
